import { createWorkflow, createAgent, createTool } from 'mastra';
import { z } from 'zod';

const invoiceSchema = z.object({
  invoiceNumber: z.string().min(1),
  date: z.string().datetime(),
  total: z.number().positive(),
  vendor: z.string(),
  lineItems: z.array(z.object({
    description: z.string(),
    amount: z.number()
  }))
});

const extractionAgent = createAgent({
  name: 'invoice_extractor',
  model: 'gpt-4o',
  instructions: 'Extract invoice data using the provided schema',
  outputSchema: invoiceSchema
});

const extractionWorkflow = createWorkflow({
  nodes: [
    {
      id: 'extract',
      agent: extractionAgent,
      input: ({ context }) => ({ documents: context.documents })
    }
  ]
});

const parseDocumentTool = createTool({
  name: 'parse_document',
  description: 'Parse document text into chunks',
  schema: z.object({
    content: z.string(),
    fileType: z.enum(['pdf', 'docx', 'txt'])
  }),
  execute: async ({ content, fileType }) => {
    // PDF/text parsing logic
    const chunks = await parseContent(content, fileType);
    return {
      chunks,
      metadata: { fileType, chunkCount: chunks.length }
    };
  }
});

extractionAgent.addTool(parseDocumentTool);

import { KnowledgeBase } from 'mastra/knowledge';

const kb = new KnowledgeBase({
  name: 'documents',
  embeddingModel: 'text-embedding-3-small'
});

const ragNode = {
  id: 'retrieve',
  type: 'knowledge_retrieval',
  knowledgeBase: kb,
  input: ({ query }) => ({ query }),
  maxResults: 5
};

extractionWorkflow.addNode(ragNode);

const validateNode = {
  id: 'validate',
  type: 'function',
  func: async (input: any) => {
    const result = invoiceSchema.safeParse(input.extractedData);
    if (!result.success) {
      throw new Error(`Validation failed: ${JSON.stringify(result.error.issues)}`);
    }
    return result.data;
  }
};

const persistNode = {
  id: 'persist',
  type: 'function',
  func: async (validatedData: any) => {
    await db.invoices.insert(validatedData);
    return { status: 'persisted', data: validatedData };
  }
};

