import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'mastra-extraction'
});

const guardedExecutor = async (input: any) => {
  const guardrail = await vex.guardrail({
    name: 'invoice_extraction',
    validations: [
      {
        type: 'pydantic_schema',
        schema: {
          type: 'object',
          properties: {
            invoiceNumber: { type: 'string' },
            date: { type: 'string', format: 'date-time' },
            total: { type: 'number', minimum: 0 },
            vendor: { type: 'string' },
            lineItems: {
              type: 'array',
              items: { type: 'object', properties: { description: { type: 'string' }, amount: { type: 'number' } } }
            }
          },
          required: ['invoiceNumber', 'date', 'total', 'vendor', 'lineItems']
        }
      },
      { type: 'completeness_check', required_fields: ['invoiceNumber', 'total'] },
      { type: 'field_accuracy', fields: ['total'], threshold: 0.95 }
    ]
  });

  const result = await guardrail.enforce({
    input: input.documents,
    agent: extractionAgent,
    context: { workflow: 'invoice_extraction' }
  });

  return result.output;
};

const toolGuardrail = await vex.guardrail({
  name: 'document_parser',
  validations: [
    {
      type: 'object_structure',
      required_keys: ['chunks', 'metadata'],
      max_array_length: { chunks: 50 }
    },
    {
      type: 'regex_match',
      field: 'metadata.fileType',
      pattern: '^(pdf|docx|txt)$'
    },
    {
      type: 'range_check',
      field: 'metadata.chunkCount',
      min: 1,
      max: 100
    }
  ]
});

const safeParseTool = createTool({
  ...parseDocumentTool,
  execute: async (params) => {
    const rawOutput = await parseDocumentTool.execute(params);
    return await toolGuardrail.enforce({
      input: params,
      output: rawOutput
    }).output;
  }
});

const workflowGuard = await vex.guardrail({
  name: 'workflow_transition',
  validations: [
    {
      type: 'context_freshness',
      max_age_hours: 24,
      fields: ['document.timestamp']
    },
    {
      type: 'data_drift',
      baseline_schema: invoiceSchema,
      drift_threshold: 0.1
    },
    {
      type: 'consistency_check',
      rules: [
        'total === lineItems.reduce((sum, item) => sum + item.amount, 0)'
      ]
    }
  ]
});

const safeTransition = async (fromNode: string, toNode: string, data: any) => {
  const result = await workflowGuard.enforce({
    input: data,
    metadata: { fromNode, toNode, timestamp: new Date().toISOString() }
  });

  if (result.valid) {
    return extractionWorkflow.executeNode(toNode, result.output);
  }
  throw new Error(`Transition failed: ${result.issues}`);
};
